#include <stdio.h>
int nthRoot(int n, int m) {
    for (int i = 1; i <= m; i++) {
        long long power = 1;
        for (int j = 0; j < n; j++) {
            power *= i;
            if (power > m) break;
        }
        if (power == m) return i;
    }
    return -1;
}

int main() {
    int n = 3, m = 27;
    printf("Nth Root: %d\n", nthRoot(n, m));
    return 0;
}

